// // This module implements a 2:1 multiplexer where the output is selected based on the value of 'sel'. When 'sel' is 0, the output is 'in1', and when 'sel' is 1, the output is 'in0'.
module mux_2to1 (
    input in0,
    input in1,
    input sel,
    output out
);

    assign out = sel ? in1 : in0;

endmodule
